public class HammingWeight {
    static int bits(int n) {
        int count = 0;
        while (n != 0) {
            count += n & 1;
            n >>>= 1;
        }
        return count;
    }
    public static void main(String[] args) {
        System.out.println(bits(0));
        System.out.println(bits(7));
        System.out.println(bits(8));
        System.out.println(bits(255));
    }
}
